"use client";

import { useState } from "react";
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  CardFooter,
} from "@/components/ui/card";
import { Textarea } from "@/components/ui/textarea";
import { Button } from "@/components/ui/button";
import { createClient } from "@/lib/supabase/client";
import { toast } from "sonner";
import { Save } from "lucide-react";

interface MedicalHistoryProps {
  patientId: string;
  initialHistory: Record<string, unknown> | null;
}

export function MedicalHistoryForm({
  patientId,
  initialHistory,
}: MedicalHistoryProps) {
  const [historyNotes, setHistoryNotes] = useState<string>(
    (initialHistory?.notes as string) || "",
  );
  const [isSaving, setIsSaving] = useState(false);
  const supabase = createClient();

  const handleSave = async () => {
    setIsSaving(true);

    // We update the medical_history jsonb column
    const { error } = await supabase
      .from("patients")
      .update({
        medical_history: {
          ...initialHistory,
          notes: historyNotes,
          last_updated: new Date().toISOString(),
        },
      })
      .eq("id", patientId);

    if (error) {
      toast.error("Erreur lors de l'enregistrement : " + error.message);
    } else {
      toast.success("Antécédents médicaux mis à jour avec succès.");
    }

    setIsSaving(false);
  };

  return (
    <Card>
      <CardHeader>
        <CardTitle>Antécédents Médicaux</CardTitle>
        <CardDescription>
          Historique de santé, allergies, et remarques générales sur le patient.
        </CardDescription>
      </CardHeader>
      <CardContent>
        <div className="space-y-4">
          <Textarea
            placeholder="Ex: Allergie à la Pénicilline, Diabète de type 2, hypertension..."
            className="min-h-[150px]"
            value={historyNotes}
            onChange={(e) => setHistoryNotes(e.target.value)}
          />
        </div>
      </CardContent>
      <CardFooter className="flex justify-end">
        <Button onClick={handleSave} disabled={isSaving}>
          <Save className="w-4 h-4 mr-2" />
          {isSaving ? "Enregistrement..." : "Enregistrer"}
        </Button>
      </CardFooter>
    </Card>
  );
}
